import{_ as e,c as t,o as a,Q as o}from"./chunks/framework.42e95ed4.js";const m=JSON.parse('{"title":"如何活的更久一点","description":"","frontmatter":{"title":"如何活的更久一点","date":"2022-03-06T09:27:37.000Z","next":{"text":"继承与组合","link":"/post/extends-and-composition"},"prev":{"text":"Koa 入门","link":"/post/koa-getting-started"}},"headers":[],"relativePath":"post/live-longer.md","filePath":"post/live-longer.md","lastUpdated":null}'),r={name:"post/live-longer.md"},n=o('<h1 id="如何活的更久一点" tabindex="-1">如何活的更久一点 <a class="header-anchor" href="#如何活的更久一点" aria-label="Permalink to &quot;如何活的更久一点&quot;">​</a></h1><p>最近看 b 站的 一个视频 <a href="https://www.bilibili.com/video/BV1f34y1r7Lt" target="_blank" rel="noreferrer">什么样的人死的更快？【围炉夜话】</a> 讲了什么样的人更长寿，什么样的人更短寿。</p><p>总结一下视频中的结论</p><h2 id="如何活得更久-物理上" tabindex="-1">如何活得更久（物理上） <a class="header-anchor" href="#如何活得更久-物理上" aria-label="Permalink to &quot;如何活得更久（物理上）&quot;">​</a></h2><p>做有氧运动，少吃甜点、饮料、果汁（糖类，精加工碳水），多吃新鲜水果，豆类，坚果，五谷杂粮，优质的低脂蛋白，远离污染，少抽烟。远离装修空气污染</p><h2 id="如何活的更久-精神上" tabindex="-1">如何活的更久（精神上） <a class="header-anchor" href="#如何活的更久-精神上" aria-label="Permalink to &quot;如何活的更久（精神上）&quot;">​</a></h2><p>少焦虑，尽量不让自己处于压力状态，尽量让自己处于挑战反应（遇到问题感到有些压力的同时更具有挑战性），少让自己处于威胁反应（遇到问题感到更大的压力）。最后，乐观且自信。</p>',7),i=[n];function l(s,d,p,_,c,h){return a(),t("div",null,i)}const u=e(r,[["render",l]]);export{m as __pageData,u as default};
